class Solution {
public:
    int possibleStringCount(string word, int k) {
        const int MOD = 1'000'000'007;
        int n = word.size();
        if (k > n) return 0;

        vector<int> lens;
        int cnt = 1;
        for (int i = 1; i < n; ++i) {
            if (word[i] == word[i-1]) {
                ++cnt;
            } else {
                lens.push_back(cnt);
                cnt = 1;
            }
        }
        lens.push_back(cnt);

        int m = lens.size();
        vector<vector<long long>> dp(m + 1, vector<long long>(n + 1, 0));
        dp[0][0] = 1;

        for (int i = 1; i <= m; ++i) {
            int len = lens[i-1];
            vector<long long> prefix(n + 2, 0);
            for (int j = 0; j <= n; ++j) {
                prefix[j+1] = (prefix[j] + dp[i-1][j]) % MOD;
            }
            for (int j = 0; j <= n; ++j) {
                int low = max(0, j - len);
                int high = j;
                dp[i][j] = (prefix[high+1] - prefix[low] + MOD) % MOD;
            }
        }

        long long res = 0;
        for (int l = k; l <= n; ++l) {
            res = (res + dp[m][l]) % MOD;
        }
        return (int)res;
    }
};
